<?php

declare(strict_types=1);

namespace App\Controllers;

use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;use App\Services\CalendarSyncService;use App\Services\CrewOperationsService;use App\Services\CustomFieldService;

final class JobController
{
 public function index():void{Auth::requireLogin();$pdo=Database::connection();$sql="SELECT j.*,c.display_name,u.name technician,cr.name crew_name FROM jobs j JOIN customers c ON c.id=j.customer_id LEFT JOIN users u ON u.id=j.assigned_user_id LEFT JOIN crews cr ON cr.id=j.crew_id";$args=[];if(Auth::role()==='technician'){$sql.=" LEFT JOIN crew_members cm ON cm.crew_id=j.crew_id AND cm.active=1 WHERE (j.assigned_user_id=? OR cm.user_id=?)";$args=[(int)Auth::id(),(int)Auth::id()];}$sql.=' ORDER BY COALESCE(j.scheduled_start,j.created_at) DESC';$s=$pdo->prepare($sql);$s->execute($args);View::render('portal/jobs/index',['title'=>'Jobs','jobs'=>$s->fetchAll()],'portal');}
 public function show(string $id):void{Auth::requireLogin();$pdo=Database::connection();$s=$pdo->prepare("SELECT j.*,c.display_name,c.email,c.phone,p.address1,p.city,p.state,p.postal_code,CONCAT_WS(', ',p.address1,p.city,p.state,p.postal_code) full_address,u.name technician,v.unit_number,cr.name crew_name FROM jobs j JOIN customers c ON c.id=j.customer_id LEFT JOIN properties p ON p.id=j.property_id LEFT JOIN users u ON u.id=j.assigned_user_id LEFT JOIN vehicles v ON v.id=j.assigned_vehicle_id LEFT JOIN crews cr ON cr.id=j.crew_id WHERE j.id=?");$s->execute([(int)$id]);$job=$s->fetch();if(!$job){http_response_code(404);exit('Job not found');}if(Auth::role()==='technician'&&!$this->canAccess($pdo,$job)){http_response_code(403);exit('Access denied');}$users=$pdo->query("SELECT id,name FROM users WHERE status='active' AND role IN ('administrator','owner','crew_leader','technician') ORDER BY name")->fetchAll();$vehicles=$pdo->query("SELECT id,unit_number FROM vehicles WHERE status='active' ORDER BY unit_number")->fetchAll();$crews=CrewOperationsService::crews($pdo);$inventory=$pdo->query("SELECT id,name,quantity,unit FROM inventory_items WHERE active=1 AND quantity>0 ORDER BY name")->fetchAll();$q=$pdo->prepare('SELECT * FROM job_checklist_items WHERE job_id=? ORDER BY sort_order,id');$q->execute([(int)$id]);$ph=$pdo->prepare('SELECT p.*,u.name uploader FROM job_photos p LEFT JOIN users u ON u.id=p.uploaded_by WHERE p.job_id=? ORDER BY p.created_at DESC');$ph->execute([(int)$id]);$usage=$pdo->prepare('SELECT ju.*,i.name,i.unit FROM job_inventory_usage ju JOIN inventory_items i ON i.id=ju.inventory_item_id WHERE ju.job_id=? ORDER BY ju.created_at DESC');$usage->execute([(int)$id]);$templates=$pdo->query("SELECT id,name FROM inspection_templates WHERE entity_type='job' AND active=1 ORDER BY name")->fetchAll();$ins=$pdo->prepare("SELECT i.*,t.name template_name,u.name completed_name FROM inspections i JOIN inspection_templates t ON t.id=i.inspection_template_id LEFT JOIN users u ON u.id=i.completed_by WHERE i.entity_type='job' AND i.entity_id=? ORDER BY i.created_at DESC");$ins->execute([(int)$id]);$history=$pdo->prepare("SELECT h.*,cr.name crew_name,u.name technician_name,v.unit_number,a.name assigned_by_name FROM job_crew_assignment_history h LEFT JOIN crews cr ON cr.id=h.crew_id LEFT JOIN users u ON u.id=h.assigned_user_id LEFT JOIN vehicles v ON v.id=h.vehicle_id LEFT JOIN users a ON a.id=h.assigned_by WHERE h.job_id=? ORDER BY h.created_at DESC LIMIT 25");$history->execute([(int)$id]);$suggestions=CrewOperationsService::suggestions($pdo,(int)$id);View::render('portal/jobs/show',['title'=>$job['job_number'],'job'=>$job,'users'=>$users,'vehicles'=>$vehicles,'crews'=>$crews,'crewSuggestions'=>$suggestions,'assignmentHistory'=>$history->fetchAll(),'inventory'=>$inventory,'usage'=>$usage->fetchAll(),'checklist'=>$q->fetchAll(),'photos'=>$ph->fetchAll(),'inspectionTemplates'=>$templates,'inspections'=>$ins->fetchAll(),'customFields'=>CustomFieldService::definitions('job'),'customValues'=>CustomFieldService::values('job',(int)$id)],'portal');}
 public function schedule(string $id):void{Auth::requireRole('owner','office','crew_leader');verify_csrf();$pdo=Database::connection();$crewId=($_POST['crew_id']??'')!==''?(int)$_POST['crew_id']:null;$userId=($_POST['assigned_user_id']??'')!==''?(int)$_POST['assigned_user_id']:null;$vehicleId=($_POST['assigned_vehicle_id']??'')!==''?(int)$_POST['assigned_vehicle_id']:null;if($crewId){$c=$pdo->prepare('SELECT crew_leader_id,default_vehicle_id FROM crews WHERE id=? AND active=1');$c->execute([$crewId]);$crew=$c->fetch();if($crew){$userId=$userId?:($crew['crew_leader_id']?:(null));$vehicleId=$vehicleId?:($crew['default_vehicle_id']?:(null));}$conflicts=CrewOperationsService::conflicts($pdo,$crewId,(string)$_POST['scheduled_start'],(string)$_POST['scheduled_end'],(int)$id);if($conflicts&&!isset($_POST['override_conflicts'])){flash('warning','Crew assignment has conflicts: '.implode(' ',$conflicts).' Check “override conflicts” to continue.');redirect('/portal/jobs/'.$id);}}$pdo->prepare("UPDATE jobs SET scheduled_start=?,scheduled_end=?,crew_id=?,assigned_user_id=?,assigned_vehicle_id=?,status='scheduled' WHERE id=?")->execute([$_POST['scheduled_start'],$_POST['scheduled_end'],$crewId,$userId,$vehicleId,(int)$id]);$pdo->prepare('INSERT INTO job_crew_assignment_history(job_id,crew_id,assigned_user_id,vehicle_id,assigned_by,assignment_source) VALUES(?,?,?,?,?,?)')->execute([(int)$id,$crewId,$userId,$vehicleId,Auth::id(),'job']);CustomFieldService::save('job',(int)$id,$_POST,Auth::id());CalendarSyncService::pushJob((int)$id);AuditService::log('job.scheduled','job',(int)$id,['crew_id'=>$crewId]);flash('success','Job scheduled and queued for Outlook synchronization.');redirect('/portal/jobs/'.$id);}
 public function status(string $id):void{Auth::requireLogin();verify_csrf();$allowed=['scheduled','in_progress','completed','cancelled'];$status=$_POST['status']??'';if(!in_array($status,$allowed,true)){flash('danger','Invalid job status.');redirect('/portal/jobs/'.$id);} $extra=$status==='in_progress'?',started_at=COALESCE(started_at,NOW())':($status==='completed'?',completed_at=NOW()':'');Database::connection()->prepare("UPDATE jobs SET status=?$extra WHERE id=?")->execute([$status,(int)$id]);AuditService::log('job.status_changed','job',(int)$id,['status'=>$status]);flash('success','Job status updated.');redirect('/portal/jobs/'.$id);}
 private function canAccess($pdo,array $job):bool{if((int)$job['assigned_user_id']===(int)Auth::id())return true;if(empty($job['crew_id']))return false;$s=$pdo->prepare('SELECT COUNT(*) FROM crew_members WHERE crew_id=? AND user_id=? AND active=1');$s->execute([(int)$job['crew_id'],(int)Auth::id()]);return (int)$s->fetchColumn()>0;}
}
